            // Position from 'a' is c.charCodeAt(0) - 'a'.charCodeAt(0)
            // Mirror position from 'z' is 25 - (c.charCodeAt(0) - 'a'.charCodeAt(0))
            // Mirror char code: 'z'.charCodeAt(0) - (c.charCodeAt(0) - 'a'.charCodeAt(0))
            const charCodeA = 'a'.charCodeAt(0);
            const charCodeZ = 'z'.charCodeAt(0);
            const offset = c.charCodeAt(0) - charCodeA;
            const mirrorOffset = 25 - offset;
            return String.fromCharCode(charCodeA + mirrorOffset);
        } else if (c >= '0' && c <= '9') {
            // Digit: '0' maps to '9', '1' maps to '8', etc.
            const charCode0 = '0'.charCodeAt(0);
            const charCode9 = '9'.charCodeAt(0);
            const digitValue = parseInt(c);
            // Mirror value: 9 - digitValue
            const mirrorValue = 9 - digitValue;
            return String.fromCharCode(charCode0 + mirrorValue);
        }
        // Should not happen based on constraints
        return c;
    };

    let totalDifference = 0;
    const processedPairs = new Set();
    const uniqueChars = Array.from(freq.keys());

    for (const c of uniqueChars) {
        if (processedPairs.has(c)) {
            continue;
        }

        const m = getMirror(c);

        // Ensure we only process the pair (c, m) once.
        // We enforce an ordering (e.g., lexicographical or based on character type)
        // to define a canonical representation for the pair.
        let primaryChar, secondaryChar;
        if (c < m) {
            primaryChar = c;
            secondaryChar = m;
        } else if (m < c) {
            primaryChar = m;
            secondaryChar = c;
        } else { // c === m (self-mirroring, e.g., 'm' and 'n' are not self-mirroring, but theoretically possible)
            primaryChar = c;
            secondaryChar = c;
        }

        // If c is the canonical representative (i.e., c <= m), we process it.
        // If c > m, then m would have already processed this pair when it iterated over m.
        if (c > m) {
            continue;
        }

        // Add both to processed set to prevent double counting when iterating over m later, 
        // although the structure above should handle it if we only check 'c' iteration.
        processedPairs.add(c);
        processedPairs.add(m);


        const freqC = freq.get(c) || 0;
        const freqM = freq.get(m) || 0;

        const difference = Math.abs(freqC - freqM);
        totalDifference += difference;
    }

    return totalDifference;
}

